const data = $input.item.json;
const job = data.job || {};
const score = data.score || {};
const runId = $('Trigger').first().json.run_id || '';
const tokens = data.tokens || { input: 0, output: 0 };
const cost = typeof data.cost === 'number' ? data.cost : 0;
const modelUsed = data.model_used || 'unknown';

// job_id: stable 8-char base62 id, minted once here (the single point a job
// first becomes a persisted row). Carried by every downstream consumer; never
// regenerated. This node runs once-per-item, so each job gets its own id.
function makeJobId() {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  let id = '';
  for (let i = 0; i < 8; i++) id += chars[Math.floor(Math.random() * 62)];
  return 'job_' + id;
}
const jobId = makeJobId();

// Serialize each dimension's {target, background} sub-scores as a JSON cell.
// Empty string for missing/malformed dimensions (preserves previous null-safety).
const dimCell = (key) => {
  const v = (score.dimensions || {})[key];
  if (!v || typeof v !== 'object') return '';
  return JSON.stringify({
    target: v.target ?? null,
    background: v.background ?? null
  });
};

const restrictionsArr = Array.isArray(score.restrictions) ? score.restrictions : [];
const restrictionsText = restrictionsArr
  .map(r => (r && r.detail) ? String(r.detail).trim() : '')
  .filter(s => s)
  .join('. ');
const restrictionsJson = JSON.stringify(restrictionsArr);

// Strengths and gaps are {target: [...], background: [...]} â€” serialize as JSON cells.
const sanitize = (obj) => ({
  target: (obj && Array.isArray(obj.target)) ? obj.target : [],
  background: (obj && Array.isArray(obj.background)) ? obj.background : []
});
const strengthsJson = JSON.stringify(sanitize(score.strengths));
const gapsJson = JSON.stringify(sanitize(score.gaps));

const descSource = String(job.description || job.description_html || '');
const descClean = descSource.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const jdSummary = descClean.slice(0, 200);

const row = {
  discovery_run_id: runId,
  company: job.company || '',
  title: job.title || '',
  url: job.url || '',
  description_html: job.description_html || '',
  jd_summary: jdSummary,
  location: job.location || '',
  remote: (job.remote === true || String(job.remote).toLowerCase() === 'true') ? 'TRUE' : '',
  salary_text: job.salary_text || '',
  source: job.source || '',
  posted_at: job.posted_at || '',
  discovered_at: new Date().toISOString(),
  discovery_tokens_in: tokens.input || 0,
  discovery_tokens_out: tokens.output || 0,
  discovery_cost_usd: Number(cost.toFixed(6)),
  discovery_model_used: modelUsed,
  build_application: '',
  // Target-driven (primary) verdict and score â€” drives the table badge
  overall_score: (typeof score.overall_score === 'number') ? score.overall_score : '',
  verdict: score.verdict || '',
  // Background-driven scoring for the side-by-side comparison popup
  background_overall_score: (typeof score.background_overall_score === 'number') ? score.background_overall_score : '',
  background_verdict: score.background_verdict || '',
  jd_score_rationale: score.rationale || '',
  // Dimension cells: {"target":N,"background":N}
  title_match: dimCell('title_match'),
  level_match: dimCell('level_match'),
  role_type_match: dimCell('role_type_match'),
  domain_match: dimCell('domain_match'),
  location_match: dimCell('location_match'),
  salary_signal: dimCell('salary_signal'),
  // Restrictions (anchor-agnostic â€” same flat shape as before)
  restrictions_text: restrictionsText,
  restrictions_json: restrictionsJson,
  // Strengths and gaps: {"target":[...],"background":[...]}
  strengths: strengthsJson,
  gaps: gapsJson,
  job_id: jobId
};

console.log(`[Build Discovery Row] run=${runId} job_id=${jobId} [${row.company}] ${row.title}: target=${row.overall_score}/${row.verdict}, background=${row.background_overall_score}/${row.background_verdict}, $${row.discovery_cost_usd.toFixed(6)}`);

return { json: row };

const scored = $('Trigger').first().json.scored_jobs || [];
if (scored.length === 0) {
  console.log('[Recorder] No scored jobs to write');
  return [];
}
console.log(`[Recorder] Writing ${scored.length} scored jobs`);
return scored.map(s => ({ json: s }));

const failures = $('Trigger').first().json.failures || [];
if (failures.length === 0) {
  console.log('[Recorder] No failures to write');
  return [];
}
console.log(`[Recorder] Writing ${failures.length} failures`);
return failures.map(f => ({ json: f }));

const usage = $('Trigger').first().json.usage || [];
if (usage.length === 0) {
  console.log('[Recorder] No usage records to write');
  return [];
}
console.log(`[Recorder] Writing ${usage.length} usage records`);
return usage.map(u => ({ json: u }));
